// GetModelSpec returns spec for a model, with sensible defaults if unknown.
func GetModelSpec(model string) ModelSpec {
	if s, ok := ModelRegistry[model]; ok { return s }
	return ModelSpec{MaxInputTokens: 128000, MaxOutputTokens: 4096, InputCostPer1M: 1.00, OutputCostPer1M: 3.00, SupportsTools: true}
}

// GetContextWindow returns the max input tokens for a model.
func GetContextWindow(model string) int { return GetModelSpec(model).MaxInputTokens }
